import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-ats-pipeline',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './ats-pipeline.component.html',
  styleUrls: ['./ats-pipeline.component.css']
})
export class AtsPipelineComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  // Stocke la liste globale des candidatures récupérées de MySQL
  applicationsList: any[] = []; 
  
  // 🚀 AJOUT : Stocke la candidature actuellement sélectionnée pour la fenêtre modale
  selectedApplication: any = null; 

  ngOnInit() {
    this.fetchApplications();
  }

  fetchApplications() {
    const targetUrl = 'http://localhost:3000/api/recruiter/ats/applications';
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(res => {
      if (!res.ok) throw new Error("Impossible de charger le pipeline ATS.");
      return res.json();
    })
    .then(data => {
      this.applicationsList = data;
      this.cdr.detectChanges();
    })
    .catch(err => console.error("Erreur ATS :", err));
  }

  // 🚀 AJOUT : Méthode déclenchée au clic sur une carte de candidat
  onSelectApplication(app: any) {
    this.selectedApplication = app;
    this.cdr.detectChanges();
    console.log("Candidature sélectionnée pour consultation :", app);
  }

  // 🚀 AJOUT : Méthode pour fermer la consultation
  onCloseDetails() {
    this.selectedApplication = null;
    this.cdr.detectChanges();
  }
}
 
<div class="ats-container">
  <div class="ats-card">
    <div class="card-header">
      <h3><i class="bi bi-people-fill"></i> Suivi des Candidats (Pipeline ATS)</h3>
      <p>Suivez pas à pas la progression de vos candidats dans le tunnel de recrutement.</p>
    </div>

    <!-- Les colonnes Kanban du logiciel de recrutement -->
    <div class="pipeline-grid">
      <div class="pipeline-column">
        <div class="column-header">Nouveaux CV <span class="count">2</span></div>
        <div class="candidate-item">
          <h5>Ahmed Ben Ali</h5>
          <p>Développeur Angular Junior</p>
          <span class="location"><i class="bi bi-geo-alt"></i> Tunis</span>
        </div>
        <div class="candidate-item">
          <h5>Marwa Tounsi</h5>
          <p>Développeur Node.js</p>
          <span class="location"><i class="bi bi-geo-alt"></i> Sousse</span>
        </div>
      </div>

      <div class="pipeline-column">
        <div class="column-header">Entretien Tech <span class="count">1</span></div>
        <div class="candidate-item border-orange">
          <h5>Sami Mansour</h5>
          <p>Ingénieur DevOps Senior</p>
          <span class="location"><i class="bi bi-geo-alt"></i> Sfax</span>
        </div>
      </div>

      <div class="pipeline-column">
        <div class="column-header">Proposition <span class="count">1</span></div>
        <div class="candidate-item border-green">
          <h5>Rania Kamel</h5>
          <p>UI/UX Designer</p>
          <span class="location"><i class="bi bi-geo-alt"></i> Ariana</span>
        </div>
      </div>
    </div>
  </div>
</div>
